  ('judicial-f0899a01-moex-00566', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依最高行政法院實務見解，下列何者非屬行政處分？', '["對公務員所為之年終考績核定為丙等", "主管建築機關對經通知而逾期未申請補辦建照執照之違建人所作成之違章建築限期拆除通知單", "戶政事務所對於有應撤銷戶籍登記事由而未依期限申請登記之人民所為申請登記之通知", "機關對於依規定在一定期間內遷出其所屬眷舍之合法現住人所提申請1次補助費作出之否准決定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
