  ('judicial-f0899a01-moex-00568', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政契約之敘述，下列何者錯誤？', '["行政機關與人民間訂定之行政契約，僅行政機關有調整權", "行政契約亦為契約之一種，故均得合意約定第一審管轄法院", "如行政機關調整與人民間所簽訂之行政契約，倘造成人民有財產上損失，應予補償", "行政機關依法終止行政契約，人民對補償金額如不同意時，得向行政法院提起給付訴訟"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00569', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列何者非行政契約無效之原因？', '["當事人無行為能力", "給付標的自始客觀不能", "行政機關為錯誤之意思表示", "代理人無代理權限"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 26, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00570', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列何者非行政事實行為？', '["就新冠肺炎之疫情說明", "命傳染病患者居家隔離", "對高齡者施打流感疫苗", "登革熱病源區域之警告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00571', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '行政罰裁處權之時效計算，其法定之停止進行原因，不包括下列何者？', '["事變", "依法律規定不能開始", "因行為人尚無法到案", "天災"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00572', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '課予刑事被告緩起訴處分金後，行政機關就同一行為再裁處罰鍰，下列敘述何者正確？', '["該緩起訴處分金屬於行政罰", "該緩起訴處分金屬於刑罰", "行政機關就同一行為再裁處罰鍰，應屬違法", "裁處罰鍰部分應扣抵緩起訴處分金之金額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00573', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政罰法規定處罰之審酌、減輕或免除，下列敘述何者正確？', '["不論處罰種類，皆應審酌行為應受責難程度、所生影響及因違反行政法義務所得之利益", "行為人所得利益超過法定罰鍰最高額者，罰鍰處分應加重罰鍰額度至所得利益之最上限", "如依其他法律有減輕罰鍰之規定，裁處之罰鍰上限得減輕至法定罰鍰最高額之三分之一", "如行為人防衛行為過當仍應受裁罰，裁處之罰鍰上限不得逾法定罰鍰最高額之三分之一"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00574', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '裁罰機關依法扣留受裁處沒入之物，所有人如不得對裁處案件之實體決定聲明不服時，依法得單獨對扣留 表示不服。此時應適用下列何種訴訟類型請求返還扣留物？', '["以撤銷訴訟請求撤銷違法之扣留命令", "以確認訴訟請求確認扣留命令為違法", "以課予義務訴訟請求廢止違法之扣留命令", "以一般給付訴訟直接請求發還扣留物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00575', 'judicial-f0899a01', 'judicial-f0899a01-moex-110-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '有關行政行為之敘述，下列何者正確？', '["警察機關認定集會遊行已違法，其命令群眾解散時，仍須以書面為之", "建管機關認定既有建築物未取得使用執照，不論其是否有補申請執照之可能，即命立即拆除", "消防機關認定餐廳違反消防法，得於同一書面，命業者限期改善並處罰鍰", "環保機關認定工廠違法排放污水，得命業者立刻改善，並即處以怠金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:48+00:00", "source_pdf_sha1": "ff136e5557ae", "answer_pdf_sha1": "c9b885251cb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "203", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
